from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single,
    fluent, complex sentence. The function groups information by subject and
    creates natural‑language clauses, using commas and conjunctions to keep the
    sentence readable.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Map each subject to a list of phrase fragments
    subject_map: dict[str, list[str]] = {}

    for t in triples:
        s = t.subject
        p = t.predicate
        o = _clean(t.object)

        # Build a phrase for the predicate
        if p == "cityServed":
            phrase = f"serves the city of {o}"
        elif p == "location":
            phrase = f"is located in {o}"
        elif p == "country":
            phrase = f"is in {o}"
        elif p == "isPartOf":
            phrase = f"is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            phrase = f"lies at an elevation of {o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            phrase = f"lies at an elevation of {o} feet above sea level"
        elif p == "operatingOrganisation":
            phrase = f"is operated by {o}"
        elif p == "runwaySurfaceType":
            phrase = f"has a runway surface of {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            phrase = f"{idx.lower()} runway is {o} feet long"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            phrase = f"{idx.lower()} runway is {o} metres long"
        elif p == "runwayName":
            phrase = f"runway is named {o}"
        elif p == "runwayLength":
            phrase = f"runway length is {o}"
        elif p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            phrase = f"{idx.lower()} runway number is {o}"
        elif p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            phrase = f"{idx.lower()} runway surface is {o}"
        else:
            phrase = f"has {p} {o}"

        subject_map.setdefault(s, []).append(phrase)

    # Build clauses for each subject
    clauses: list[str] = []
    for subj, phrases in subject_map.items():
        if not phrases:
            continue
        # Join phrases with commas and an 'and' before the last one
        if len(phrases) == 1:
            clause_body = phrases[0]
        else:
            clause_body = ", ".join(phrases[:-1]) + f", and {phrases[-1]}"
        clauses.append(f"{subj} {clause_body}")

    # Combine all clauses into one complex sentence
    sentence = "; ".join(clauses) + "."
    # Ensure first character is capitalised
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

